import socketimport jsonimport threadingimport timedevices = []stop_event = threading.Event()#Постоянно орёт, что он существует и отправляет свои данныеdef scream():    this_devise = json.dumps({"hostname": socket.gethostbyname(socket.gethostname()), 'name':socket.gethostname(), "port": 8080})    server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)    server.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, True)    server.sendto(this_devise.encode("utf-8"), ("192.168.0.255",8080))    print(f"Отправлено широковещательное сообщение: {this_devise}")    server.close()def listener(timeout = 3):    client = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)    client.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, True)    client.bind(('0.0.0.0', 8080))    print(f"Поиск устройств в сети ({timeout} сек)...")    start_time = time.time()    while time.time() - start_time < timeout:        data = client.recv(1024)        msg = json.loads(data.decode("utf-8"))        if not any(d['hostname'] == msg['hostname'] for d in devices):            devices.append(msg)            print(f"Найдено устройство: {msg['name']} ({msg['hostname']})")    return devices